[FormDataSourceEventHandler(formDataSourceStr(PurchTable, PurchTable), FormDataSourceEventType::Activated)]
public static void PurchTable_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun formRun = sender.formRun();

    FormStringControl placeOfLoading   = formRun.design().controlName(formControlStr(PurchTable, PlaceOfLoading));
    FormStringControl placeOfDischarge = formRun.design().controlName(formControlStr(PurchTable, PlaceOfDischarge));

    if (ETG_Parameters::find().ValidatePortOfDischargeField == NoYes::Yes)
    {
        placeOfDischarge.mandatory(true);
    }
    if (ETG_Parameters::find().ValidatePortOfLoadingField == NoYes::Yes)
    {
        placeOfLoading.mandatory(true);
    }
}

[FormDataSourceEventHandler(formDataSourceStr(PurchTable, PurchTable), FormDataSourceEventType::ValidatingWrite)]
public static void PurchTable_OnValidatingWrite(FormDataSource sender, FormDataSourceEventArgs e)
{
    ETGPurchTableFormEventHandler::validatePorts(sender.formRun(), e);
}

