private static void validatePorts(FormRun formRun, FormDataSourceEventArgs e)
{

    FormDataSource      etgTradeDs = formRun.dataSource(formDataSourceStr(PurchTable, ETG_PurchTableTrade));
    ETG_PurchTableTrade etgTrade   = etgTradeDs.cursor();
    ETG_Parameters      params     = ETG_Parameters::find();
    boolean             ok         = true;

    FormDataSourceCancelEventArgs cancelArgs = e as FormDataSourceCancelEventArgs;

    if (params.ValidatePortOfLoadingField == NoYes::Yes && !etgTrade.PortOfLoading)
    {
        ok = checkFailed("Place of loading must be filled in.") && ok;
    }

    if (params.ValidatePortOfDischargeField == NoYes::Yes && !etgTrade.PortOfDischarge)
    {
        ok = checkFailed("Place of discharge must be filled in.") && ok;
    }

    if (!ok && cancelArgs)
    {
        cancelArgs.cancel(true);
    }
}

[FormDataSourceEventHandler(formDataSourceStr(PurchTable, PurchLine), FormDataSourceEventType::ValidatingWrite)]
public static void PurchLine_OnValidatingWrite(FormDataSource sender, FormDataSourceEventArgs e)
{
    ETGPurchTableFormEventHandler::validatePorts(sender.formRun(), e);
}
